using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

builder.Logging.SetMinimumLevel(LogLevel.Warning);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in config or OPENAI_API_KEY env var.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<ResearchNotes>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var notes = host.Services.GetRequiredService<ResearchNotes>();

var tools = new ResearchTools(notes);

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. When given a topic, use the web_search " +
    "tool to find information. Use save_note to record important findings. " +
    "After gathering enough information (at least 3 searches), use " +
    "get_all_notes to review your notes, then provide a concise summary " +
    "with key findings and sources.");

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 15,
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools =
        [
            AIFunctionFactory.Create(tools.WebSearch),
            AIFunctionFactory.Create(tools.SaveNote),
            AIFunctionFactory.Create(tools.GetAllNotes),
        ],
    },
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n📝 Notes collected during research:");
foreach (var note in notes.GetNotes())
{
    Console.WriteLine($"  • {note}");
}

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("A research topic is required.")
        : input;
}

// --- Tools and supporting types ---

public sealed class ResearchNotes
{
    private readonly List<string> _notes = [];
    private readonly Lock _lock = new();

    public void Add(string note)
    {
        lock (_lock) { _notes.Add(note); }
    }

    public IReadOnlyList<string> GetNotes()
    {
        lock (_lock) { return [.. _notes]; }
    }
}

public sealed class ResearchTools(ResearchNotes notes)
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information on a query. Returns search result snippets.")]
    public async Task<string> WebSearch(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("Abstract", out var abs) &&
                abs.GetString() is { Length: > 0 } abstract_)
            {
                var source = root.TryGetProperty("AbstractSource", out var src)
                    ? src.GetString() : "Unknown";
                results.Add($"[{source}] {abstract_}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        text.GetString() is { Length: > 0 } snippet)
                    {
                        var firstUrl = topic.TryGetProperty("FirstURL", out var fu)
                            ? fu.GetString() : "";
                        results.Add($"{snippet} (Source: {firstUrl})");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : "No results found. Try rephrasing the query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save an important finding or note during research.")]
    public string SaveNote(
        [Description("The note text to save")] string note)
    {
        notes.Add(note);
        Console.WriteLine($"  📌 Note saved ({notes.GetNotes().Count} total)");
        return $"Note saved. Total notes: {notes.GetNotes().Count}";
    }

    [Description("Retrieve all saved research notes to review before summarizing.")]
    public string GetAllNotes()
    {
        var allNotes = notes.GetNotes();
        if (allNotes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n", allNotes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

